1	package com.fortinet.nac.ingestion.consumer.orchestrator;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.redis.DistributedLock;
6	import com.fortinet.nac.common.util.StatusOr;
7	
8	import com.fortinet.nac.ingestion.consumer.MockData;
9	import com.fortinet.nac.ingestion.consumer.handler.*;
10	import com.fortinet.nac.ingestion.delayqueue.RedisDelayQueueUtil;
11	import com.fortinet.nac.ingestion.entity.Entity;
12	import com.fortinet.nac.ingestion.service.EntityService;
13	
14	import com.fortinet.nac.ingestion.util.EntityCache;
15	import com.fortinet.nac.ingestion.util.RedisUtil;
16	import org.junit.jupiter.api.Test;
17	import org.junit.jupiter.api.extension.ExtendWith;
18	
19	import org.mockito.InjectMocks;
20	import org.mockito.Mock;
21	import org.mockito.junit.jupiter.MockitoExtension;
22	
23	import static org.mockito.Mockito.*;
24	import static org.junit.jupiter.api.Assertions.*;
25	
26	@ExtendWith(MockitoExtension.class)
27	class IngestionOrchestratorTest {
28	
29	    @InjectMocks
30	    private IngestionOrchestrator orchestrator;
31	
32	    @Mock private EntityCache entityCache;
33	    @Mock private EntityService entityService;
34	    @Mock private DistributedLock distributedLock;
35	    @Mock private RedisDelayQueueUtil redisDelayQueueUtil;
36	
37	    @Mock private NewEntityHandler newEntityHandler;
38	    @Mock private CachedExistingEntityHandler cachedExistingEntityHandler;
39	    @Mock private DbExistingEntityHandler dbExistingEntityHandler;
40	
41	    private final IngestionRequest req = MockData.req();
42	    private final long entityId = 100L;
43	    private final Entity entity = MockData.entity(entityId);
44	
45	    // ------------------------------------------------------------
46	    // CASE 1: Entity does not exist -> invoke NewEntityHandler
47	    // ------------------------------------------------------------
48	    @Test
49	    void testNewEntityPath() {
50	        String existKey = RedisUtil.getExistKey(req);
51	
52	        // 1) Cache miss
53	        when(entityCache.getCachedEntityId(existKey)).thenReturn(null);
54	
55	        // 2) Create-lock acquired
56	        when(distributedLock.tryLock(anyString(), anyLong())).thenReturn(true);
57	
58	        // 3) DB returns no entity
59	        when(entityService.getEntity(req)).thenReturn(null);
60	
61	        Entity newEntity = MockData.entity(entityId);
62	
63	        // 4) newEntityHandler should be invoked
64	        when(newEntityHandler.handle(req)).thenReturn(StatusOr.ok(newEntity));
65	
66	        StatusOr<Entity> result = orchestrator.process(req);
67	
68	        assertTrue(result.ok());
69	        assertEquals(entityId, result.getValue().getId());
70	
71	        verify(entityCache).getCachedEntityId(existKey);
72	        verify(distributedLock).tryLock(anyString(), anyLong());
73	        verify(entityService).getEntity(req);
74	        verify(newEntityHandler).handle(req);
75	        verify(distributedLock).unLock(anyString());
76	
77	        verifyNoInteractions(cachedExistingEntityHandler);
78	        verifyNoInteractions(dbExistingEntityHandler);
79	    }
80	
81	    // ------------------------------------------------------------
82	    // CASE 2: EntityId exists in cache -> invoke CachedExistingEntityHandler
83	    // ------------------------------------------------------------
84	    @Test
85	    void testCachedEntityPath() {
86	        String existKey = RedisUtil.getExistKey(req);
87	
88	        // 1) Cache hit
89	        when(entityCache.getCachedEntityId(existKey)).thenReturn(200L);
90	
91	        Entity e = MockData.entity(200);
92	
93	        // 2) Directly go to cachedExistingEntityHandler
94	        when(cachedExistingEntityHandler.handle(req, 200L))
95	                .thenReturn(StatusOr.ok(e));
96	
97	        StatusOr<Entity> result = orchestrator.process(req);
