941	    private Entity waitUntilFingerprintChangedAndEnforced(IngestionRequest req, String oldFp) {
942	        return await()
943	                .atMost(Duration.ofSeconds(10))
944	                .pollInterval(Duration.ofMillis(100))
945	                .until(() -> {
946	                    Entity e = entityService.getEntity(req);
947	                    if (e == null) return null;
948	
949	                    boolean fpChanged = !Objects.equals(e.getAttributeFingerprint(), oldFp);
950	                    boolean enforced = EntityStage.ENFORCED.toString().equals(e.getProcessingStage());
951	
952	                    if (fpChanged && enforced) {
953	                        return e;
954	                    }
955	                    return null;
956	                }, Objects::nonNull);
957	    }
