960	    private void waitForConsumerReady(String stream, String group, long timeoutMs) {
961	        long start = System.currentTimeMillis();
962	
963	        while (System.currentTimeMillis() - start < timeoutMs) {
964	            try {
965	                // Fetch consumers under the given group
966	                RStream<String, String> redisStream = redissonClient.getStream(stream);
967	                // Check if the consumer group exists by trying to get pending info
968	                try {
969	                    PendingResult pendingInfo = redisStream.getPendingInfo(group);
970	                    System.out.println("Consumer group registered in Redis: " + group);
971	                    return;
972	                } catch (Exception e) {
973	                    // Consumer group not yet created
974	                }
975	
976	            } catch (Exception ignore) {}
977	
978	            sleep(200);
979	        }
980	
981	        throw new RuntimeException("Timeout waiting for Redis consumer startup");
982	    }
983	
984	    private void waitEntityEnforced(IngestionRequest req, long timeoutMs) {
985	        long start = System.currentTimeMillis();
986	        Throwable last = null;
987	
988	        while (System.currentTimeMillis() - start < timeoutMs) {
989	            try {
990	                Entity e = entityService.getEntity(req);
991	                if (e != null && EntityStage.ENFORCED.toString().equals(e.getProcessingStage())) {
992	                    return;
993	                }
994	
995	            } catch (Throwable t) {
996	                last = t;
997	                t.printStackTrace();
998	            }
999	
1000	            sleep(100);
1001	        }
1002	
1003	        throw new RuntimeException("Timeout waiting for ENFORCED state, last=" + last, last);
1004	    }
