53	
54	            // put traceId into MDC for current thread so logback [%X{traceId}] works
55	            try (MDC.MDCCloseable ignored = MDC.putCloseable(Constants.TRACE_ID, traceId)) {
56	
57	                log.info("REST ingestion request arrived: requestId={}", req.getRequestId());
58	
59	                // Step 2: register callback future
60	                CompletableFuture<ResultDTO<?>> future =
61	                    callbackRegistry.register(req.getRequestId());
62	
63	                // Add a timeout to the future itself to ensure the registry does not have memory leak.
64	                //
65	                // If the internal processing never calls callbackRegistry.complete(...)
66	                // (e.g., consumer crash, message loss, or the message stays pending forever),
67	                // the registry would otherwise leak memory.
68	                future.orTimeout(responseTimeout, TimeUnit.SECONDS)
69	                        .whenComplete((r, e) -> callbackRegistry.unregister(req.getRequestId()));
70	
71	                // Step 3: publish message
72	                boolean ok = producer.sendEvent(
73	                    Constants.RedisStream.INGESTION_INTERNAL_STREAM_KEY, req);
74	                if (!ok) {
75	                    callbackRegistry.unregister(req.getRequestId());
76	                    return Mono.just(ResultDTO.error(HTTP_INTERNAL_SERVER_ERROR, "failed to publish message"));
77	                }
78	
79	                // wait for internal consumer to finish future
80	                return Mono.fromFuture(future);
81	            }
82	        })
83	
84	        // Move all logic inside the defer block onto nettyOffloadExecutor thread pool to
85	        // avoid blocking the Netty event loop.
86	        .subscribeOn(Schedulers.fromExecutor(nettyOffloadExecutor))
87	        .onErrorResume(e -> {
88	            // unwrap CompletionException / ExecutionException
89	            Throwable t = e;
90	            if (t instanceof CompletionException || t instanceof ExecutionException) {
91	                if (t.getCause() != null) t = t.getCause();
92	            }
93	            if (t instanceof TimeoutException) {
94	                return Mono.just(ResultDTO.success("Request received but still processing", req.getTraceId()));
95	            }
96	            return Mono.just(ResultDTO.error(HTTP_INTERNAL_SERVER_ERROR, "internal error: " + e.getMessage()));
97	        })
98	        .doFinally(sig -> MDC.remove(Constants.TRACE_ID));
99	    }
